import java.util.HashMap;
import java.util.Map;

public class Solution {
    public static long solve(long[][] points) {
        final long MOD = 1_000_000_007;
        Map<Long, Integer> yCount = new HashMap<>();
        for (long[] p : points) {
            long y = p[1];
            yCount.put(y, yCount.getOrDefault(y, 0) + 1);
        }
        long inv2 = (MOD + 1) / 2;
        long S = 0;
        long S2 = 0;
        for (int count : yCount.values()) {
            long c = count;
            long temp = (c * (c - 1)) % MOD;
            long term_mod = (temp * inv2) % MOD;
            S = (S + term_mod) % MOD;
            long term_sq = (term_mod * term_mod) % MOD;
            S2 = (S2 + term_sq) % MOD;
        }
        long S_squared = (S * S) % MOD;
        long numerator = (S_squared - S2 + MOD) % MOD;
        long ans = (numerator * inv2) % MOD;
        return ans;
    }
}
